import cv2
import math
import os
import urllib.request

import mediapipe as mp
from mediapipe.tasks import python
from mediapipe.tasks.python import vision


class HandDetector:
    """
    Hand Tracking using latest MediaPipe Tasks API
    CVZone-compatible output
    """

    MODEL_URL = "https://storage.googleapis.com/mediapipe-models/hand_landmarker/hand_landmarker/float16/1/hand_landmarker.task"
    MODEL_NAME = "hand_landmarker.task"

    def __init__(self,
                 staticMode=False,
                 maxHands=2,
                 modelComplexity=1,
                 detectionCon=0.5,
                 minTrackCon=0.5):

        self.staticMode = staticMode
        self.maxHands = maxHands
        self.detectionCon = detectionCon
        self.minTrackCon = minTrackCon

        self.tipIds = [4, 8, 12, 16, 20]

        self._downloadModel()

        base_options = python.BaseOptions(
            model_asset_path=self.MODEL_NAME
        )

        options = vision.HandLandmarkerOptions(
            base_options=base_options,
            num_hands=self.maxHands,
            running_mode=vision.RunningMode.VIDEO
        )

        self.detector = vision.HandLandmarker.create_from_options(options)

        self.timestamp = 0

    # ---------------------------
    # Auto Download Model
    # ---------------------------
    def _downloadModel(self):
        if not os.path.exists(self.MODEL_NAME):
            print("Downloading MediaPipe Hand model...")
            urllib.request.urlretrieve(self.MODEL_URL, self.MODEL_NAME)
            print("Download complete.")

    # ---------------------------
    # Main Function
    # ---------------------------
    def findHands(self, img, draw=True, flipType=True):

        imgRGB = cv2.cvtColor(img, cv2.COLOR_BGR2RGB)

        mp_image = mp.Image(
            image_format=mp.ImageFormat.SRGB,
            data=imgRGB
        )

        result = self.detector.detect_for_video(mp_image, self.timestamp)
        self.timestamp += 1

        allHands = []
        h, w, _ = img.shape

        if result.hand_landmarks:

            for i, hand_landmarks in enumerate(result.hand_landmarks):

                myHand = {}
                lmList = []
                xList = []
                yList = []

                for lm in hand_landmarks:

                    x, y = int(lm.x * w), int(lm.y * h)

                    lmList.append([x, y, 0])
                    xList.append(x)
                    yList.append(y)

                xmin, xmax = min(xList), max(xList)
                ymin, ymax = min(yList), max(yList)

                boxW, boxH = xmax - xmin, ymax - ymin

                bbox = (xmin, ymin, boxW, boxH)
                cx, cy = xmin + boxW // 2, ymin + boxH // 2

                # Hand type not always provided reliably in Tasks API
                handType = "Unknown"

                myHand["lmList"] = lmList
                myHand["bbox"] = bbox
                myHand["center"] = (cx, cy)
                myHand["type"] = handType

                allHands.append(myHand)

                if draw:
                    cv2.rectangle(
                        img,
                        (xmin - 20, ymin - 20),
                        (xmax + 20, ymax + 20),
                        (255, 0, 255),
                        2
                    )

                    cv2.circle(img, (cx, cy), 5, (0, 255, 0), -1)

        return allHands, img

    # ---------------------------
    # Finger Counter (same logic)
    # ---------------------------
    def fingersUp(self, myHand):

        fingers = []
        lmList = myHand["lmList"]

        # Thumb
        if lmList[self.tipIds[0]][0] > lmList[self.tipIds[0] - 1][0]:
            fingers.append(1)
        else:
            fingers.append(0)

        # 4 fingers
        for id in range(1, 5):
            if lmList[self.tipIds[id]][1] < lmList[self.tipIds[id] - 2][1]:
                fingers.append(1)
            else:
                fingers.append(0)

        return fingers

    # ---------------------------
    # Distance (unchanged)
    # ---------------------------
    def findDistance(self, p1, p2, img=None, color=(255, 0, 255), scale=5):

        x1, y1 = p1
        x2, y2 = p2

        cx, cy = (x1 + x2) // 2, (y1 + y2) // 2

        length = math.hypot(x2 - x1, y2 - y1)

        info = (x1, y1, x2, y2, cx, cy)

        if img is not None:
            cv2.circle(img, (x1, y1), scale, color, -1)
            cv2.circle(img, (x2, y2), scale, color, -1)
            cv2.line(img, (x1, y1), (x2, y2), color, 2)
            cv2.circle(img, (cx, cy), scale, color, -1)

        return length, info, img

def main():
    # Initialize the webcam to capture video
    # The '2' indicates the third camera connected to your computer; '0' would usually refer to the built-in camera
    cap = cv2.VideoCapture(2)

    # Initialize the HandDetector class with the given parameters
    detector = HandDetector(staticMode=False, maxHands=2, modelComplexity=1, detectionCon=0.5, minTrackCon=0.5)

    # Continuously get frames from the webcam
    while True:
        # Capture each frame from the webcam
        # 'success' will be True if the frame is successfully captured, 'img' will contain the frame
        success, img = cap.read()

        # Find hands in the current frame
        # The 'draw' parameter draws landmarks and hand outlines on the image if set to True
        # The 'flipType' parameter flips the image, making it easier for some detections
        hands, img = detector.findHands(img, draw=True, flipType=True)

        # Check if any hands are detected
        if hands:
            # Information for the first hand detected
            hand1 = hands[0]  # Get the first hand detected
            lmList1 = hand1["lmList"]  # List of 21 landmarks for the first hand
            bbox1 = hand1["bbox"]  # Bounding box around the first hand (x,y,w,h coordinates)
            center1 = hand1['center']  # Center coordinates of the first hand
            handType1 = hand1["type"]  # Type of the first hand ("Left" or "Right")

            # Count the number of fingers up for the first hand
            fingers1 = detector.fingersUp(hand1)
            print(f'H1 = {fingers1.count(1)}', end=" ")  # Print the count of fingers that are up

            # Calculate distance between specific landmarks on the first hand and draw it on the image
            length, info, img = detector.findDistance(lmList1[8][0:2], lmList1[12][0:2], img, color=(255, 0, 255),
                                                      scale=10)

            # Check if a second hand is detected
            if len(hands) == 2:
                # Information for the second hand
                hand2 = hands[1]
                lmList2 = hand2["lmList"]
                bbox2 = hand2["bbox"]
                center2 = hand2['center']
                handType2 = hand2["type"]

                # Count the number of fingers up for the second hand
                fingers2 = detector.fingersUp(hand2)
                print(f'H2 = {fingers2.count(1)}', end=" ")

                # Calculate distance between the index fingers of both hands and draw it on the image
                length, info, img = detector.findDistance(lmList1[8][0:2], lmList2[8][0:2], img, color=(255, 0, 0),
                                                          scale=10)

            print(" ")  # New line for better readability of the printed output

        # Display the image in a window
        cv2.imshow("Image", img)

        # Keep the window open and update it for each frame; wait for 1 millisecond between frames
        cv2.waitKey(1)


if __name__ == "__main__":
    main()
